+  chain.push({
+    hash: sourceHash,
+    label: 'source',
+    parent: null,
+  });
+
+  // One node per decompiled module
+  for (const mod of modules) {
+    const modHash = sha256(mod.content);
+    moduleHashes.push({ name: mod.name, hash: modHash });
